Use MSTest's `[DataTestMethod]` with `[DataRow]` to make these data-driven. Each new case becomes a single attribute line:

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Validation.Tests;

[TestClass]
public sealed class InputValidatorTests
{
    private InputValidator _validator = null!;

    [TestInitialize]
    public void Setup() => _validator = new InputValidator();

    [DataTestMethod]
    [DataRow("", false, "Input cannot be empty", DisplayName = "Empty string")]
    [DataRow(null, false, "Input cannot be empty", DisplayName = "Null")]
    [DataRow("   ", false, "Input cannot be empty", DisplayName = "Whitespace only")]
    [DataRow("ab", false, "Input must be at least 3 characters", DisplayName = "Too short")]
    [DataRow("hello<script>", false, "Input contains invalid characters", DisplayName = "Special chars")]
    [DataRow("abc", true, null, DisplayName = "Min length")]
    [DataRow("hello-world", true, null, DisplayName = "Valid input")]
    public void Validate_ReturnsExpectedResult(string? input, bool expectedValid, string? expectedError)
    {
        var result = _validator.Validate(input);
        Assert.AreEqual(expectedValid, result.IsValid);
        Assert.AreEqual(expectedError, result.ErrorMessage);
    }

    // DataRow can't construct objects, so keep edge cases that need
    // computed inputs (like max-length strings) as separate methods.
    [DataTestMethod]
    [DataRow(256, false, "Input must not exceed 255 characters", DisplayName = "Too long")]
    [DataRow(255, true, null, DisplayName = "Max length")]
    public void Validate_LengthBoundary_ReturnsExpectedResult(int length, bool expectedValid, string? expectedError)
    {
        var result = _validator.Validate(new string('a', length));
        Assert.AreEqual(expectedValid, result.IsValid);
        Assert.AreEqual(expectedError, result.ErrorMessage);
    }
}
```

**Key improvements:**
- **Adding a case** = adding one `[DataRow]` line instead of a whole method
- **`[TestInitialize]`** removes the repeated `new InputValidator()` setup
- **`DisplayName`** gives each row a readable name in Test Explorer
- Cases needing computed inputs (like `new string(...)`) go in a second parameterized method since `[DataRow]` only accepts compile-time constants
